-- all_events(): the entire log in global order — the SQL equivalent of EventStoreDB's $all stream.
-- Inspection/replay only (projections track a checkpoint on position); never a read path.
-- all_events()  ==  SELECT * FROM domain_events ORDER BY position
CREATE FUNCTION all_events()
RETURNS SETOF domain_events
LANGUAGE sql STABLE AS $$
  SELECT * FROM domain_events ORDER BY position;
$$;

-- ce_events(category): every event whose stream belongs to one category, chronological — the SQL
-- equivalent of EventStoreDB's $ce-<category> projection. Inspection/replay only; read paths use View_*.
-- ce_events('Catalog')  ==  SELECT * FROM domain_events WHERE stream_name LIKE 'Catalog-%'
CREATE FUNCTION ce_events(category TEXT)
RETURNS SETOF domain_events
LANGUAGE sql STABLE AS $$
  SELECT *
  FROM domain_events
  WHERE split_part(stream_name, '-', 1) = category
  ORDER BY stream_name, version;
$$;

-- enforce_max_count(): AFTER-INSERT trigger function backing domain_events' $maxCount. Trims the
-- inserted event's stream to the last N versions, where N is that stream's domain_stream.max_count
-- (no row / NULL = unbounded). Bound by trg_domain_events_max_count (see tables.yaml).
CREATE FUNCTION enforce_max_count() RETURNS trigger LANGUAGE plpgsql AS $$
DECLARE cap INT;
BEGIN
  SELECT max_count INTO cap FROM domain_stream WHERE stream_name = NEW.stream_name;
  IF cap IS NOT NULL THEN
    DELETE FROM domain_events
    WHERE stream_name = NEW.stream_name
      AND version <= NEW.version - cap;   -- keep only the last `cap` versions of this stream
  END IF;
  RETURN NULL;                            -- AFTER ROW trigger
END;
$$;

-- et_events(event_type): every event of one type across all streams, in global order — the SQL
-- equivalent of EventStoreDB's $et-<type> projection. Inspection/replay only; read paths use View_*.
-- et_events('RestaurantRegistered')  ==  SELECT * FROM domain_events WHERE event_type = 'RestaurantRegistered'
CREATE FUNCTION et_events(event_type TEXT)
RETURNS SETOF domain_events
LANGUAGE sql STABLE AS $$
  SELECT *
  FROM domain_events
  WHERE domain_events.event_type = et_events.event_type
  ORDER BY position;
$$;

-- Retention sweep for the write-path journals and adapter webhook mirrors
-- (ADR-20260721-025159; issue #18). The ONE place the retention windows live — schedule it from
-- the in-process RetentionSweepWorker (default) or a pg_cron job; either way the policy is here.
--
-- Scope, per table (aged rows only — the guard columns are the tables' own high-water marks):
--   command_journal            terminal rows (SUCCEEDED/REJECTED/FAILED)  90 days from completed_at
--   inbound_events             DELIVERED rows                             30 days from delivered_at
--   external_stripe_events     processed rows (processed_at set)          90 days from processed_at
--   external_hubrise_callbacks processed rows (processed_at set)          90 days from processed_at
--   external_avelo37_events    processed rows (processed_at set)          90 days from processed_at
--   external_uber_direct_events processed rows (processed_at set)         90 days from processed_at
--
-- NEVER swept, at any age: domain_events / domain_stream (the forever log — deliberately not
-- referenced here; its only trimming is the opt-in per-stream $maxAge/$maxCount machinery),
-- command_journal RECEIVED rows (the stale-RECEIVED sweep marks crashed runs FAILED first),
-- inbound_events FAILED rows (kept until resolved) and RECEIVED rows (pending work),
-- unprocessed mirror rows (processed_at IS NULL), and external_sirene_restaurants (a full
-- mirror — detect-by-absence needs the complete row set, ADR-0045).
CREATE FUNCTION sweep_retention()
RETURNS TABLE (swept_table TEXT, deleted BIGINT)
LANGUAGE plpgsql
AS $$
DECLARE
  n BIGINT;
BEGIN
  -- Status predicates resolve through the ref_* enum lookups (ADR-0037 ordinals) — never
  -- hard-coded integers.
  DELETE FROM command_journal
   WHERE status IN (SELECT sort_order FROM ref_command_journal_status
                     WHERE value IN ('SUCCEEDED', 'REJECTED', 'FAILED'))
     AND completed_at IS NOT NULL
     AND completed_at < now() - INTERVAL '90 days';
  GET DIAGNOSTICS n = ROW_COUNT;
  swept_table := 'command_journal'; deleted := n; RETURN NEXT;

  DELETE FROM inbound_events
   WHERE status = (SELECT sort_order FROM ref_inbound_event_status WHERE value = 'DELIVERED')
     AND delivered_at IS NOT NULL
     AND delivered_at < now() - INTERVAL '30 days';
  GET DIAGNOSTICS n = ROW_COUNT;
  swept_table := 'inbound_events'; deleted := n; RETURN NEXT;

  DELETE FROM external_stripe_events
   WHERE processed_at IS NOT NULL
     AND processed_at < now() - INTERVAL '90 days';
  GET DIAGNOSTICS n = ROW_COUNT;
  swept_table := 'external_stripe_events'; deleted := n; RETURN NEXT;

  DELETE FROM external_hubrise_callbacks
   WHERE processed_at IS NOT NULL
     AND processed_at < now() - INTERVAL '90 days';
  GET DIAGNOSTICS n = ROW_COUNT;
  swept_table := 'external_hubrise_callbacks'; deleted := n; RETURN NEXT;

  DELETE FROM external_avelo37_events
   WHERE processed_at IS NOT NULL
     AND processed_at < now() - INTERVAL '90 days';
  GET DIAGNOSTICS n = ROW_COUNT;
  swept_table := 'external_avelo37_events'; deleted := n; RETURN NEXT;

  DELETE FROM external_uber_direct_events
   WHERE processed_at IS NOT NULL
     AND processed_at < now() - INTERVAL '90 days';
  GET DIAGNOSTICS n = ROW_COUNT;
  swept_table := 'external_uber_direct_events'; deleted := n; RETURN NEXT;
END;
$$;

CREATE TRIGGER trg_domain_events_max_count AFTER INSERT ON domain_events FOR EACH ROW EXECUTE FUNCTION enforce_max_count();
